import React, { useState } from "react";
import "../styles/GeneralChat.css";

const greetings = ["hi", "hello", "hey", "hai", "thanks", "thank"];

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hello. I'm glad you reached out today. How are you feeling right now?"
    }
  ]);
  const [input, setInput] = useState("");

  const therapistReply = (userText) => {
    const text = userText.toLowerCase().trim();

    if (greetings.some(g => text.includes(g))) {
      return "Hello. I'm glad you reached out today. How are you feeling right now?";
    }

    if ((text.includes("good") || text.includes("fine") || text.includes("okay")) && !text.includes("not")) {
      return "That's wonderful to hear. Is there anything on your mind that brings you here today? Sometimes even when things seem fine, there can be underlying concerns we're working through.";
    }

    if (text.includes("stress") || text.includes("overwhelm") || text.includes("anxious")) {
      return "Thank you for sharing that. When you say you're feeling overwhelmed, can you tell me a bit more about what's been contributing to those feelings? What stands out most for you right now?";
    }

    if (text.includes("study") || text.includes("exam") || text.includes("school") || text.includes("work") || text.includes("job")) {
      return "That sounds like a lot to manage at once. It's understandable to feel pressured when you have multiple responsibilities. How have you been coping with this so far? What strategies have you tried?";
    }

    if (text.includes("family") || text.includes("parent") || text.includes("mother") || text.includes("father")) {
      return "Family dynamics can really shape how we feel. Thank you for trusting me with this. Can you share more about what these expectations mean to you and how they're affecting your daily life?";
    }

    if (text.includes("keep") || text.includes("inside") || text.includes("alone") || text.includes("myself")) {
      return "I appreciate your honesty. Keeping things inside can be exhausting and isolating. We can explore healthier ways to express and process these feelings together, at a pace that feels comfortable for you. What would help you feel safer sharing?";
    }

    if (text.includes("sad") || text.includes("depressed") || text.includes("hopeless") || text.includes("empty")) {
      return "Thank you for opening up about this. These feelings are valid and more common than you might think. Can you tell me how long you've been feeling this way and if there was a specific trigger or if it's been gradual?";
    }

    if (text.includes("sleep") || text.includes("tired") || text.includes("eat") || text.includes("appetite")) {
      return "Changes in sleep and appetite often reflect how our mind is processing stress. These are important signals from your body. How has this been affecting your daily functioning?";
    }

    if (text.includes("help") || text.includes("advice") || text.includes("what should")) {
      return "I'm here to support you. Rather than telling you what to do, I'd like to help you discover your own strengths and resources. What do you think might be a helpful first step for you?";
    }

    return "Thank you for sharing that with me. Can you help me understand a bit more about how this has been affecting you day to day? I want to make sure I'm fully understanding your experience.";
  };

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = { sender: "user", text: input };
    const botMessage = {
      sender: "bot",
      text: therapistReply(input)
    };

    setMessages([...messages, userMessage, botMessage]);
    setInput("");
  };

  const handleKeyPress = (e) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2 className="chat-title">💬 Professional Therapy Chat</h2>
        <p className="chat-subtitle">A safe space to share your feelings</p>
      </div>

      <div className="chat-box">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`message-group ${msg.sender === "user" ? "user-group" : "therapist-group"}`}
          >
            <div className="message-label">
              {msg.sender === "user" ? "You" : "Therapist"}
            </div>
            <div className={`message ${msg.sender === "user" ? "user" : "bot"}`}>
              {msg.text}
            </div>
          </div>
        ))}
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Share your thoughts safely..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={handleKeyPress}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
